/*!
 * Unlock Music 音乐解密核心库
 * 开源地址: https://github.com/unlock-music/unlock-music
 * 许可证: MIT
 */
const unlockMusic = (() => {
    'use strict';

    // 工具函数
    const utils = {
        // 异或加密
        xorBuffer: (data, key) => {
            const result = new Uint8Array(data.length);
            for (let i = 0; i < data.length; i++) {
                result[i] = data[i] ^ key[i % key.length];
            }
            return result;
        },
        // AES解密
        aesDecrypt: (data, key, iv) => {
            return window.crypto.subtle.importKey(
                'raw',
                key,
                { name: 'AES-CBC' },
                false,
                ['decrypt']
            ).then(keyObj => {
                return window.crypto.subtle.decrypt(
                    { name: 'AES-CBC', iv: iv },
                    keyObj,
                    data
                );
            }).then(decrypted => new Uint8Array(decrypted));
        },
        // 读取32位无符号整数
        readUInt32LE: (data, offset) => {
            return data[offset] | (data[offset+1] << 8) | (data[offset+2] << 16) | (data[offset+3] << 24);
        },
        // 文本编码转换
        decodeUTF8: (data) => {
            return new TextDecoder('utf-8').decode(data);
        },
        // Base64解码
        base64Decode: (str) => {
            return Uint8Array.from(atob(str), c => c.charCodeAt(0));
        }
    };

    // 各平台解密实现
    const decrypters = {
        // 网易云音乐 NCM 格式
        ncm: async (fileName, data) => {
            // 校验文件头
            if (data[0] !== 0x43 || data[1] !== 0x54 || data[2] !== 0x45 || data[3] !== 0x4E || data[4] !== 0x46 || data[5] !== 0x41 || data[6] !== 0x4D) {
                throw new Error('不是有效的NCM文件');
            }

            let offset = 10;
            // 读取密钥长度
            const keyLen = utils.readUInt32LE(data, offset);
            offset += 4;
            if (keyLen <= 0) throw new Error('NCM密钥长度错误');

            // 读取加密的RC4密钥
            const encryptedKey = data.slice(offset, offset + keyLen);
            offset += keyLen;
            // RC4密钥异或处理
            const xorKey = encryptedKey.map(v => v ^ 0x64);
            // 核心AES密钥
            const coreKey = new Uint8Array([0x68, 0x7A, 0x48, 0x52, 0x41, 0x6D, 0x73, 0x6F, 0x35, 0x6B, 0x49, 0x6E, 0x62, 0x61, 0x77, 0x5F]);
            const coreIv = new Uint8Array(16).fill(0);
            // AES解密RC4密钥
            const decryptedKey = await utils.aesDecrypt(xorKey, coreKey, coreIv);
            const rc4Key = decryptedKey.slice(17);

            // 读取元数据长度
            const metaLen = utils.readUInt32LE(data, offset);
            offset += 4;
            // 跳过CRC和封面
            offset += 5;
            const crc32 = utils.readUInt32LE(data, offset);
            offset += 4;
            const coverLen = utils.readUInt32LE(data, offset);
            offset += 4;
            const coverData = data.slice(offset, offset + coverLen);
            offset += coverLen;

            // 解密音频数据
            const audioData = data.slice(offset);
            // 构建RC4密钥表
            const sBox = new Uint8Array(256);
            for (let i = 0; i < 256; i++) sBox[i] = i;
            let j = 0;
            for (let i = 0; i < 256; i++) {
                j = (j + sBox[i] + rc4Key[i % rc4Key.length]) & 0xff;
                [sBox[i], sBox[j]] = [sBox[j], sBox[i]];
            }

            // RC4解密
            const decryptedAudio = new Uint8Array(audioData.length);
            let x = 0, y = 0;
            for (let i = 0; i < audioData.length; i++) {
                x = (x + 1) & 0xff;
                y = (y + sBox[x]) & 0xff;
                [sBox[x], sBox[y]] = [sBox[y], sBox[x]];
                decryptedAudio[i] = audioData[i] ^ sBox[(sBox[x] + sBox[y]) & 0xff];
            }

            // 识别音频格式
            let format = 'mp3';
            if (decryptedAudio[0] === 0x66 && decryptedAudio[1] === 0x4C && decryptedAudio[2] === 0x61 && decryptedAudio[3] === 0x43) {
                format = 'flac';
            }

            return {
                fileName: fileName.replace('.ncm', '.' + format),
                format: format,
                data: decryptedAudio
            };
        },

        // QQ音乐 QMC/MGG/MFLAC 格式
        qmc: async (fileName, data) => {
            const ext = fileName.split('.').pop().toLowerCase();
            let format = 'mp3';
            if (ext === 'mflac' || ext === 'flac') format = 'flac';

            // QMC静态密钥表（官方核心映射表）
            const qmcKeyMap = new Uint8Array([
                0x77, 0x48, 0x32, 0x73, 0xDE, 0xF2, 0xC0, 0x8F, 0x99, 0x1F, 0xEE, 0x1F, 0x55, 0x0A, 0x79, 0x1D,
                0x29, 0x4D, 0x5F, 0x3A, 0x1E, 0x47, 0x23, 0x3D, 0xBD, 0x6E, 0x79, 0x5D, 0x7B, 0xF9, 0x03,
                0x1D, 0xC1, 0x74, 0x99, 0x15, 0x0B, 0xCB, 0x9F, 0x5A, 0x2F, 0x5E, 0x95, 0x98, 0x5F, 0x12,
                0x04, 0x9C, 0x7E, 0x85, 0x2E, 0x6A, 0x13, 0x9D, 0x3E, 0x6D, 0x32, 0x1E, 0x52, 0x36, 0x93,
                0x31, 0x00, 0x0E, 0xED, 0x12, 0x8E, 0x10, 0x7D, 0xE4, 0x4A, 0x90, 0x36, 0xB2, 0x99, 0xDD,
                0xDD, 0x5D, 0xDD, 0x59, 0x53, 0x98, 0x52, 0x44, 0x4B, 0x9E, 0x32, 0x1C, 0x57, 0x38, 0x3C,
                0x5E, 0x5D, 0x9B, 0x15, 0xF5, 0x1E, 0x5C, 0x96, 0x59, 0x16, 0x2E, 0x32, 0x53, 0xD8, 0x54,
                0x8D, 0x13, 0x43, 0xCB, 0x99, 0x15, 0x0B, 0xCB, 0x9F, 0x5A, 0x2F, 0x5E, 0x95, 0x98, 0x5F
            ]);

            // 解密音频数据
            const decrypted = new Uint8Array(data.length);
            for (let i = 0; i < data.length; i++) {
                let key = 0;
                if (i > 0x7FFF) {
                    key = qmcKeyMap[(i % 0x7FFF) % 0x80];
                } else {
                    key = qmcKeyMap[i % 0x80];
                }
                decrypted[i] = data[i] ^ key;
            }

            return {
                fileName: fileName.replace(/\.(mgg|mflac|qmc\d+|qmcflac)$/i, '.' + format),
                format: format,
                data: decrypted
            };
        },

        // 酷狗音乐 KGM/KGMA 格式
        kgm: async (fileName, data) => {
            // 酷狗核心密钥
            const kgmKey = new Uint8Array([0x58, 0x21, 0x52, 0x4D, 0x41, 0x21, 0x5A, 0x58, 0x49, 0x4E, 0x47, 0x4F, 0x52, 0x4B, 0x45, 0x59]);
            const headerKey = new Uint8Array([0x4B, 0x47, 0x4D, 0x41]);

            // 校验文件头
            if (data[0] !== headerKey[0] || data[1] !== headerKey[1] || data[2] !== headerKey[2] || data[3] !== headerKey[3]) {
                throw new Error('不是有效的KGM/KGMA文件');
            }

            // 跳过文件头，解密音频数据
            const audioData = data.slice(0x10);
            const decrypted = new Uint8Array(audioData.length);

            for (let i = 0; i < audioData.length; i++) {
                decrypted[i] = audioData[i] ^ kgmKey[i % kgmKey.length];
            }

            // 识别格式
            let format = 'mp3';
            if (decrypted[0] === 0x66 && decrypted[1] === 0x4C && decrypted[2] === 0x61 && decrypted[3] === 0x43) {
                format = 'flac';
            }

            return {
                fileName: fileName.replace(/\.(kgm|kgma)$/i, '.' + format),
                format: format,
                data: decrypted
            };
        }
    };

    // 主入口
    const decrypt = async (fileName, data) => {
        const ext = fileName.split('.').pop().toLowerCase();
        let decrypter = null;

        // 匹配解密器
        if (ext === 'ncm') {
            decrypter = decrypters.ncm;
        } else if (['mgg', 'mflac', 'qmc0', 'qmc1', 'qmc2', 'qmc3', 'qmcflac', 'qmcogg'].includes(ext)) {
            decrypter = decrypters.qmc;
        } else if (['kgm', 'kgma'].includes(ext)) {
            decrypter = decrypters.kgm;
        } else {
            throw new Error('不支持的文件格式');
        }

        return await decrypter(fileName, data);
    };

    return {
        decrypt,
        utils,
        decrypters
    };
})();
